-- Generated from service_descriptions_with_analysts.xlsx service descriptions.
-- Updates canonical reference.service descriptions by service_id.

UPDATE reference.service AS service
SET service_description = seed.service_description,
    updated_at = now()
FROM (VALUES
    ('SRV0100', 'The service is the legislative branch of City government, as stated in the City Charter. The City Council is comprised of the President and Council Members from 14 single member districts. The goal of this service is to be a conduit through which the public’s concerns and issues can be addressed. Activities performed by this service include enacting laws, holding hearings on topics of public interest, holding oversight hearings on various topics including monitoring the City’s budget, confirming certain municipal officers, and conducting regular meetings.'),
    ('SRV0103', 'This service provides professional staff support to the designated committees of the Baltimore City Council, analyzes all legislation pending before the City Council and analyzes local problems that require legislation. This service assists the Baltimore City Office of Information Technology (BCIT) in providing access to City Council committee hearings in-person and electronically; provides analysis for the Ordinance of Estimates for the City Council; and arranges committee hearings and meetings as requested by the City Council.'),
    ('SRV0106', 'This service furnishes information, conducts policy research, and drafts laws and regulations for legislators, public officials, and citizens. The goal of this service is to assist legislators, public officials, and residents access and analyze information pertaining to City code. Activities performed by this service include: drafting all legislation for the Mayor and City Council, editing, compiling, and publishing the City Charter, Public Local Laws, City Code, and Code of Baltimore Regulations Annotated; and collecting, indexing, and making accessible information upon which to base legislation or to guide administrative officials in performing their duties.'),
    ('SRV0107', 'This service is the central depository for City government records. The goal of this service is to help City agencies improve their retention, management, and disclosure of public records in accordance with State and local law. This service also identifies, acquires, describes, preserves, and provides access to records deemed to have permanent historical value. Activities performed by this service include: the development and implementation of Citywide policies and procedures for the management of City records; and the collection, dissemination, and administration the City’s historical records.'),
    ('SRV0109', 'This service is responsible for the overall guidance and direction of the Agency. The goal of the service is to advance the agency’s goal of activating and engaging youth around policies impacting the City’s children and families. Activities performed by this service include: leading the Children’s Cabinet and Youth Commission, co-chairing the city’s Trauma-Informed Care Task Force, and supporting the nomination process for the Board of School Commissioners. The service also supports administrative oversight and grants management for the agency.'),
    ('SRV0110', 'This service is a part of the Judiciary of Maryland, a co-equal branch of government established by Article IV of the State 
Constitution of Maryland to preside over the Eighth Judicial Circuit. The Baltimore City Circuit Court has 35 positions or 
judges who rotate among the civil, domestic, juvenile, and criminal dockets, 15 recalled senior judges who assist the court as needed on various dockets, and 14 Magistrates. Key activities performed by this service include the processing of criminal, civil, and family cases.'),
    ('SRV0111', 'No service description; we do not print Svc 111 in the book'),
    ('SRV0115', 'This service, in conjunction with its partners in law enforcement, investigates and prosecutes criminal cases occurring 
within the City of Baltimore. The goal of this service is to represent the citizens of Baltimore City in the prosecution of 
criminal offenses. Activities performed by this service include the cases in District Court, Juvenile Court, and Circuit Court processing of expungement petitions filed by, or on behalf of, former defendants.'),
    ('SRV0117', 'This service is responsible for providing an administrative hearing process for City residents, property owners, and businesses through the use of contracted administrative hearing officers.  This service also educates residents on City code requirements, provides support and resources for local communities, and distributes grants for cleaning and greening projects.  The goal of this service is to assist in changing behavior relating to quality of life and public safety issues that fall under the agency''s jurisdiction.  Activities performed by this service include the adjudication of environmental citations, the adjudication of water bill disputes and Water-4-All denials, the offering of the diversion program, and the administration of the BMORE Beautiful peer-to-peer program.'),
    ('SRV0121', 'N/a - no service description for this agency; only agency level description'),
    ('SRV0122', 'No service description; we just have an agency level description'),
    ('SRV0123', 'N/a - no service description for this agency; only agency level description'),
    ('SRV0124', 'N/a - no service description for this agency; only agency level description'),
    ('SRV0125', 'This service provides Citywide executive leadership through the City Administrator, Chief of Staff, Deputy Mayors, and Directors, as well as management of multiple activities and offices to support this work. The goal of this service is to manage and coordinate activities between City agencies and partner organizations to achieve the Administration’s goals. Activities performed by this service include the issuance of policies, directives, and initiatives to support direction and operation of municipal agencies.'),
    ('SRV0126', 'N/a - no service description for this agency; only agency level description'),
    ('SRV0128', 'This service conducts labor contract negotiations with eight City unions; meets and confers with one managerial and professional society; negotiates collective bargaining agreements with respect to wages, hours, benefits and other terms and conditions of employment. The goal of this service is to represent the City’s interest in labor relations with employee unions. Activities performed by this service include: handling grievance hearings, leading contract negotiations, making recommendations and updating policies/procedures regarding labor/management matters, and overseeing the Joint Apprenticeship Training Program.'),
    ('SRV0129', 'N/a - no service description for this agency; only agency level description'),
    ('SRV0130', 'This service provides executive leadership and administrative support for the Office of the Comptroller. The goal of this service is to provide transparency and accountability to residents of Baltimore. Activities performed by this service include oversight and support, budget development and fiscal operations, asset management, hiring and recruitment, communications and community partnerships, information technology services, and management duties for the Board of Estimates.'),
    ('SRV0131', 'This service conducts biennial performance audits and financial audits, including the City’s Annual Comprehensive Financial Report (ACFR) and Single Audit, attestation engagements and advisory services as requested. The goal of this service is to ensure that the City is spending money in line with ACFR standards. Activities performed by this service include investigating allegations of fraud, waste, and abuses of City resources and reviewing various contracts, and performing audit checks on procurement change orders and actions submitted to the Board of Estimates for approval.'),
    ('SRV0132', 'This service is responsible for leasing, acquiring, and disposing of City-owned assets. The goal of this service is to ensure that City owned and leased property meet the needs of current occupants while ensuring real estate actions are performed in accordance with all relevant laws and regulations. Activities performed by this service include: reviewing real estate-related transactions and development proposals for City-owned real property, maintaining the public inventory of City-owned and leased properties, and negotiating lease agreements on behalf of the City.'),
    ('SRV0133', 'This service provides telephone service to all City agencies and City call centers. The goal of this service is to meet the phone needs of all agencies and call centers. Activities conducted by this service include billing for products and services, business service reviews, managing Voice over Internet Protocol (VoIP) phone service, supplying mobile devices, and providing technical support, installation, and maintenance for various City call centers.'),
    ('SRV0136', 'This service oversees management of the City’s mail, facilitating interagency mail services and serves as an intermediary with the United States Postal Service for incoming and outgoing mail for City agencies and quasi-agencies. The goal of this service is to provide timely and efficient mail service to agencies. Activities performed by this service include preparing, collecting and distributing mail.'),
    ('SRV0148', 'This service collects all money that is due to the City through various taxes, fines, fees and penalties. The goal of this service is to provide a system where customers can pay most bills in person, online, using a smartphone, over the telephone, or by mail. Activities performed by this service include operating a call center to address payment and billing questions during normal business hours. This service sustains and enhances citywide operations for the government and the residents of Baltimore.'),
    ('SRV0150', 'This service manages the City’s cash, investments, debt, and banking services. The goal of this service is to provide oversight and control of the City’s cash and debt management practices in accordance with City policy and best practices. Activities performed by this service include issuing different forms of debt, managing relationships with credit rating agencies, overseeing the City’s cash investments, and serving as staff to the Board of Finance.'),
    ('SRV0152', 'This service oversees the administration associated with providing retirement, survivor, and permanent disability benefits for City employees and their beneficiaries. The goal of this service is to provide excellent member services while  administering the investment and protection of system’s assets. Activities performed by this service include payment of monthly benefits to retirees and beneficiaries, actuarial census data and valuation as well as the calculation of annual employer contributions, and overseeing the annual financial audit.'),
    ('SRV0154', 'This service oversees the administration associated with providing retirement, survivor, and permanent disability benefits for sworn City employees and their beneficiaries. The goal of this service is to provide excellent member services for the sworn Fire and Police department employees while administering the investment and protection of system’s assets. Activities performed by this service include making payments for recurring retirement benefits including post-retirement benefit increases, lump-sum death payments, and refunds of accumulated member contributions, as well as administering the System.'),
    ('SRV0155', 'This service manages the Retirement Savings Plan of the City of Baltimore (RSP) and the City of Baltimore Deferred Compensation Plan (DCP). The goal of this service is to provide resources for all City employees to be retirement ready and to be able to retire with dignity. Activities performed by this service include educating employees on available retirement options, and providing resources for City employees to ensure they are retirement ready.'),
    ('SRV0168', 'N/a - no longer a service'),
    ('SRV0185', 'This service administers, interprets, and implements the City’s zoning and municipal codes.  The goal of this service is to ensure proper land use and development through the application of the appropriate City Code and apply the relevant law to the facts presented. The service is also responsible for implementing the City''s Comprehensive Master Plan for land use development throughout Baltimore City.  Activities performed by this service include providing public notice on land use appeals, scheduling zoning hearings, and hearing municipal appeals from various City agencies.'),
    ('SRV0189', 'This service is responsible for purchasing, outfitting, fueling, maintaining, and decommissioning vehicles and other equipment used by 29 City agencies. The goal of this service is to support customer agencies in the delivery of City services by procuring and servicing over 5,600 assets that make up the City’s fleet. Activities performed by this service include vehicle purchases and retirement (decommissioned), vehicle inventory management, managing the City''s fueling systems, and maintaining and repairing the City’s motorized assets. The service is also working towards long-term goals of electrifying the City’s fleet.'),
    ('SRV0303', 'This service provides access to preventive healthcare, diagnosis, and treatment of communicable and noncommunicable diseases for Baltimore City residents. Its primary goal is the ongoing operation of our clinics and provision of sexual health, dental, and tuberculosis care for City resident -- especially the most vulnerable populations. Activities by this service include STD and HIV clinics and mobile clinic, Baltimore Disease Control (BDC) Laboratory, Tuberculosis clinic, and Oral Health Services (OHS) Program. Collectively, these clinics serve around 16,000 patients per year, who total over 18,000 visits per year.'),
    ('SRV0305', 'This service operates programs to reduce exposure to lead, asthma triggers, pesticides, and injury hazards, primarily through home visits and inspections. The goal of this service is to conduct educational home visits to children with elevated blood lead levels (EBLs), conduct environmental inspections of homes in which children with EBLs reside, and bring landlords into compliance with lead-related sections of the Baltimore City Health Code and The Code of Maryland Regulations. Activities performed by this service include offering training in asthma management, lead safety, integrated pest management, and other healthy homes topics in community-based settings.'),
    ('SRV0307', 'This service oversees the City’s behavioral health care system that addresses emotional health and well-being of vulnerable residents and provides services for substance use and mental health disorders. The goal of this service is to advocate for and guide innovative approaches to prevention, early intervention, treatment and recovery for those who are dealing with mental health and substance use disorders to help build healthier individuals, stronger families and safer communities. Activities performed by this service include advocacy to raise public health awareness of mental health and substance abuse, education and outreach efforts around this topic, allocating resources for substance use and mental health services to Baltimore providers.'),
    ('SRV0308', 'This service operates programs to promote positive birth outcomes, including a nurse home-visiting program, services to
infants and toddlers identified with a developmental delay, nutrition support, reproductive health services for teens and
adults, as well as fetal, infant, child, and maternal mortality reviews. The goal of this service is to reduce fetal, infant, and
maternal mortality and to reduce the teen birth rate. Activities performed by this service include preconception health to
adolescents and young adults, home visiting, early intervention services, WIC, morality reviews, and the population-based B''more for Healthy Babies initiative.'),
    ('SRV0310', 'This service provides delivery and coordination of health services in health suites and School-Based Health Centers
(SBHCs) to students enrolled in Baltimore City Public Schools (City Schools). The goal of this service is to ensure that
health services are available which would allow children, especially those with disabilities, to be educated in the least
restrictive environment, which is within the school building. Activities performed by this service include early nursing
intervention in elementary schools; skilled nursing management for children with special health needs; mandated
screening for hearing and vision impairments; mandated immunizations; health case management; and coordination with
other services including primary care, mental health and substance abuse services.'),
    ('SRV0311', 'This service promotes health, improves the quality of life, and prevents the premature institutionalization of Baltimore City older adults and persons with disabilities. The goal of this service is to assist functionally and chronically ill individuals who are at risk of institutionalization, offer nurse monitoring visits as optional older adult support, and provide community services and supports to enable older adults and people with disabilities to live in their own homes. Activities performed by this service include Adult Evaluation and Review Services (AERS), Community Personal Assistance Services (CPAS), and the Medicaid Waiver Program.'),
    ('SRV0315', 'This service addresses urgent public health needs in Baltimore City by responding to public health emergencies. The goal of this service is to respond to cases of reportable communicable diseases and outbreaks and transport chronically ill patients to medical appointments. Activities performed by this service include building capacity for communicable disease investigation and mitigation activities, as well as planning, training, and preparation for large-scale public health emergencies such as pandemics and bioterrorism incidents.'),
    ('SRV0316', 'This service uses public health and human service models to provide mental health referrals and other stabilization services to victims of violence and other residents impacted by trauma and violence. The goal of this service is to facilitate Trauma Informed Care (TIC) Trainings, coordinate suicide prevention efforts, and support youth exposed to violence and trauma. Activities performed by this service include citywide trauma trainings and violence prevention programs in City Schools.'),
    ('SRV0351', 'N/a - no service description for this agency; only agency level description'),
    ('SRV0352', 'N/a - no service description for this agency; only agency level description'),
    ('SRV0355', 'N/a - no service description for this agency; only agency level description'),
    ('SRV0356', 'This service provides executive leadership and administrative support for the agency. The goal of this service is to oversee and implement daily operations through coordination and strategic planning. Activities performed by this service include oversight of contracts administered by the agency, budget development and fiscal operations, grant management, hiring and recruitment, and communications and community partnerships.'),
    ('SRV0385', 'This service provides grants to the Family League of Baltimore City for pre and post natal service, the Legal Aid Bureau, and the Maryland School for the Blind. These grants fund home visiting services for expecting and new mothers, legal support for landlord tenant issues, and tuition support for students enrolled in the Maryland School for the Blind.'),
    ('SRV0446', 'This service provides grants to non-profit organizations that conduct historical, educational, and promotional activities in the City of Baltimore.  Current grantees include the Family League of Baltimore City for the Community Schools and Out of School Time programs, Baltimore City Community College (BCCC), and the Baltimore Children and Youth Fund (BCYF).'),
    ('SRV0493', 'This service provides grants to non-profit organizations that provide art, cultural, and educational programming. The goals of this service are to enhance the City’s role as a cultural center; drive economic growth; and attract tourists. Organizations that receive grant funding by this service include the Walters Art Museum, the Baltimore Museum of Art, the Baltimore Symphony Orchestra, and the Maryland Zoo in Baltimore.'),
    ('SRV0500', 'This service is responsible for designing, installing, maintaining, and inspecting the City’s network of 79,000 roadway and pedestrian lights. The goal of this service is to reduce crime while lowering the energy footprint of the lights. Activities performed by this service include: engineering and design services associated with maintaining the network of lights and overseeing the maintenance and repair of streetlights.'),
    ('SRV0535', 'N/a - no service description for this agency'),
    ('SRV0540', 'This service was established to provide funding for the Royal Farms Arena, now CFG Bank Arena, Baltimore’s largest indoor arena. The arena, which can accommodate 14,000 guests, provides a venue for a wide array of sporting and entertainment offerings. In Fiscal 2023, OVG, a private management company, began operating the City-owned facility. Under the new management agreement, a direct subsidy supporting operations is no longer required as OVG’s management fee is deducted from taxes owed to the City.'),
    ('SRV0548', 'This service is responsible for maintaining approximately 741 miles of conduit network in the City. The goal of our service is to keep the network in proper working order to carry electrical, telephone, and fiber optic lines. Activities performed by this service include contract oversight of the current agreement with BGE along with inspecting and testing the network.'),
    ('SRV0590', 'This service provides grants to non-profit organizations that conduct historical, educational, and promotional activities in Baltimore. The goal of this service is to promote tourism development, economic growth, preservation, and conservation. Organizations that receive grant funding by this service include Baltimore Public Markets, Lexington Market, and the Baltimore National Heritage Area.'),
    ('SRV0593', 'This service is responsible for the overall administration of the Community Development Block Grant (CDBG) program. The goal of this service is to connect residents with a variety of socio-economic programs by supporting grants to local nonprofits and advance the City''s Comprehensive Vacant Reduction & Prevention Strategy. Key activities performed by this service include: overseeing the development and implementation of the CDBG grant, and administering the Community Catalyst program.'),
    ('SRV0600', 'This service provides agency wide executive leadership and direct support functions including budget and financial oversight, IT and HR management for the department, and general administrative services. The goal of this service is to maintain overall continuity for the purpose of guiding the Department. Activities performed by this service include developing and implementing a comprehensive approach to emergency response, medical service delivery, fire cause determination, and fire prevention activities. This is achieved through extensive public engagement, as well as continuous professional development which is supported by on-going research into current standards and proven best practices.'),
    ('SRV0602', 'This service protects City residents and millions of annual visitors by providing 24/7 land and marine fire protection, emergency medical service, emergency rescue, and hazardous material mitigation.  The BCFD is an Insurance Services Office (ISO) 1 rated department that is built in an "All Hazards"  response fashion.  The goal of this service is to deliver high-quality fire suppression, specialized rescue, and hazardous materials response to residents and visitors within the City of Baltimore.  Activities performed by this service include fire suppression, rescue, and hazardous materials response through a coordinated system. This service responds 24/7/365 to all types of emergencies.'),
    ('SRV0604', 'This service is responsible for child care centers servicing up to 30 students. The goal of this service is to provide safe, convenient and flexible childcare to parents who work, attend school or participate in job training programs. Activities include operating the Waverly Early Childcare Center.'),
    ('SRV0605', 'This service oversees City-operated or otherwise supported Head Start locations. The goal of this service is to provide early childhood and family development resources for low-income children (ages 3-5) and their families. Activities performed by the service include:  contract management and oversight for programs receiving City funding, and providing technical assistance, as well as training, to providers.'),
    ('SRV0608', 'This service prepares the City for major emergencies such as hurricanes, power outages, hazardous materials incidents, and acts of terrorism.  This service manages interagency and public-private sector programs to prevent, mitigate against, and plan for all hazards.  The goal of this service is to strengthen federal, state, and regional coordination on joint efforts 
focused on violence prevention, intervention, enforcement, and re-entry.  Activities performed by this service include adopting a regional emergency response partnership with neighboring counties for disaster relief.  This service also provides 24/7 field response and Citywide coordination for incidents and events that are high risk, prolonged, widespread, 
or complex.'),
    ('SRV0609', 'This service provides 24/7 response, assessment, treatment, and hospital transport of trauma and medical patients.  The service responds to 180,000 EMS incidents and transports just under 90,000 patients annually.  The goal of this service is to reduce overall response times to high priority calls, with a focus on harm reduction.  Activities performed by this service include  911 call response, EMS billing, quality assurance, staff training, infection control, and Population Health services to reduce 911 calls.'),
    ('SRV0610', 'This service provides outreach and education to the City’s residents, businesses, and visitors on fire safety, fire prevention, and emergency medical services.  The goal of this service is to empower residents to gain insight and interact with their Fire Department through apparatus displays and fire & life safety presentations at community events.  Activities performed by this service include training for ‘Hands-Only CPR’, ‘Stroke Awareness’, and ‘Stop the Bleed’.'),
    ('SRV0611', 'This service works closely with the Code Enforcement team in the Department of Housing and Community Development  to ensure all new commercial and residential construction within the City meets the established fire code.  This includes testing and approval of fire protection systems, plans review of new sprinkler systems, fire alarms, etc., and reviewing 
architectural plans for "Life Safety Code" compliance.  The goal of this service is to reduce the likelihood of fires by ensuring buildings meet safety regulations.  Activities performed by this service include conducting building inspections, plans review, and fire safety equipment testing for 5,852 multi-family dwellings, 11,385 rental units, 83,706 single family dwelling units, and 13,500 commercial buildings.'),
    ('SRV0612', 'This service investigates and tracks the cause of fire to focus on fire prevention efforts, issue product recalls, and prosecute arson crimes.  The goal of this service is to reduce the loss of life, injuries, and property damage resulting from fires.  The Fire Investigation Bureau determines whether a crime has occurred through conducting investigations into the origins and causes of fires and providing crucial information to law enforcement for criminal prosecution. Activities performed by this service include investigating the origin and cause of fires, explosions, and potential arson related crimes.  Additionally, the Fire Investigation Bureau is responsible for testing and reporting defective electrical products, collecting fire data, develop targeted education through Community Risk Reduction, and reporting trends to help reduce injuries and death from fires.'),
    ('SRV0613', 'This service is responsible for maintaining and improving the Department’s building and equipment assets. The goal of this service is to improve, maintain, and repair the Department’s building and equipment assets to reduce overall response times to high priority calls, with a focus on harm reduction.  Activities performed by this service include overseeing capital projects at fire stations, coordinating with Fleet Management regarding procuring and maintaining apparatus, and coordinating personal protective gear, medical supply equipment, and drug inventories.'),
    ('SRV0614', 'This service processes approximately 1.4 million Fire and EMS calls received through the Computer Aided Dispatch system (CAD). The Fire Communications Bureau (FCB) dispatches approximately 350,000 Fire and EMS calls for service annually.  The goal of this service is to quickly facilitate the dispatch of public safety resources for 911 calls. Activities 
performed by this service include 24/7 staffing of the Auxiliary Communications Center (ACC), monitoring all main active channels, which provides rapid assessment for appropriate emergency dispatch.'),
    ('SRV0615', 'This service tests and trains Fire Academy recruits to maintain staffing levels and promote a workforce whose diversity reflects Baltimore City. This service also provides continuing education, professional development, and skills enhancement for existing fire suppression and emergency service personnel. And endeavors to reduce the number of line of duty injuries and illness to personnel, safeguard citizens, and minimize the City’s financial and legal liabilities. Activities performed by this service include developing and implementing a comprehensive approach to EMS workforce recruitment, hiring, retention, professional development, and planning.'),
    ('SRV0621', 'This service is responsible for managing and planning the efficient, effective, and equitable allocation of resources for the Baltimore Police Department. The goal of this service is to work collaboratively with internal and external partners to manage and report on the impact of the Department’s operations. Activities performed by this service include operational support for the Police Commissioner’s Office, Fiscal Services and Grants, Asset Management, Human Resources, and the Administrative Duties Division.'),
    ('SRV0622', 'This service is responsible for police district operations and responding to daily 911 calls. The goal of this service is to respond to calls for service based on policing best practices. Activities performed by service by include conducting investigations of various crime types and proactive community outreach and engagement.'),
    ('SRV0623', 'This service is responsible for investigating and enforcing the law related to serious crimes. The goal of this service is to reduce violent crime and sustain reductions in criminal activity. Activities performed by this service include investigative sections devoted to specific crime types and task force groups that work alongside federal law enforcement and partner agencies.'),
    ('SRV0626', 'This service is responsible for collecting, analyzing, and disseminating intelligence and crime data. The goal of this service is to help departmental bureaus and divisions monitor their performance and maintain accountability internally. Activities performed by this service include developing macro- and micro-level strategies for preventing, reducing, and deterring crime and ensuring that data is available to district commanders to aid them in the crime fight. The service also provides data on crime trends, patterns, proactivity, and geographies of concern so that the resources of the BPD can be effectively managed to respond to residents’ concerns.'),
    ('SRV0628', 'This service is responsible for investigating claims of police misconduct brought internally and externally to ensure the highest standards of police performance and conduct. The goal of this service is to conduct fair, thorough, objective, and timely investigations of all allegations of potential officer misconduct, while treating all individuals with dignity and respect without preference or discrimination. Activities performed by this service include investigating all serious use of force incidents, including police-involved shootings, allegations of discourtesy, excessive force, and criminal activity.'),
    ('SRV0635', 'This service is responsible for recruiting sworn personnel for the department and administering the Police Academy to train new recruits. The goal of this service is to support hiring and staffing for the agency through a regular recruiting schedule. Activities performed by this service include visits to area high schools, colleges, universities, and job fairs, helping to facilitate the interview process for new recruits, overseeing background investigations completed on applicants to ensure they meet Maryland and Baltimore Police Department standards, and preparing new recruits for the training academy.'),
    ('SRV0642', 'This service is responsible for identifying, collecting, analyzing, and safeguarding evidence. The goal of this service is to objectively convey empirical data and adhere to the highest quality standards while promoting a team-focused environment. Activities performed by this service include DNA analysis, latent print analysis, firearms analysis, forensic screening (i.e., serological analysis and latent print development), drug analysis, crime scene processing, photography services, evidence preservation, storage, and trace analysis. This includes work conducted in multiple laboratories and storage facilities and provides 24-hour crime scene service to the City of Baltimore.'),
    ('SRV0644', 'This service provides executive leadership and administrative support for the agency. The goal of this service is to oversee and implement daily operations through coordination and strategic planning. Activities performed by this service include oversight and planning of capital projects, budget development and fiscal operations, asset management, hiring and recruitment, communications and community partnerships, and information technology services.'),
    ('SRV0645', 'This service is responsible for providing swimming opportunities to the public year-round. The goal of this service is to allow residents to engage in physical activities at the various aquatic locations throughout the City. Activities performed by this service include the operations of the City’s six large park pools, 14 neighborhood walk-to-pools, four indoor pools, and the ABC, Solo Gibbs, North Hartford, and Henrietta Lax splash pads.'),
    ('SRV0646', 'This service is responsible for maintaining 4,600 acres of parkland spread over 276 individual sites, including Druid Hill, Clifton, Patterson, Gwynns Falls, and Carroll Parks. The goal of this service is to maintain and expand green spaces throughout the City to contribute to clean and healthy environments for City residents. Activities performed by this service include maintaining, cleaning, and repairing playgrounds, trails, fields, athletic courts, and park areas.'),
    ('SRV0647', 'This service provides oversight, management, and coordination of competitive sporting activities in City parks, community centers, arenas, and school facilities. The goal of this service is to engage with City youth and ensure that families have access to recreational activities. Activities for this service include the clinics and leagues for boxing, indoor/outdoor soccer, skateboarding, track and field, baseball, football, basketball, hockey, lacrosse, broomball, tennis, and rugby.'),
    ('SRV0648', 'This service operates the City’s 45 recreation centers which promote physical activity and healthy lifestyles for City residents. The goal of this service is to offer safe spaces for children, families, and seniors for recreation programming and special activities. Activities performed by this service include recreation programming, educational opportunities, and neighborhood and community events for residents.'),
    ('SRV0649', 'This service operates seven special enterprise facilities throughout the City of Baltimore. The goal of this service is to provide recreation, leisure, and educational activities for residents of Baltimore and the surrounding communities. Activities performed within this service include recreation opportunities at Carrie Murray Nature Center and Pre-School, Du Burns Arena, Mount Pleasant Ice Rink, Mimi DiPietro Ice Rink, Myers Soccer Pavilion, Middle Branch Rowing Club and Shake and Bake Family Fun Center.'),
    ('SRV0650', 'This service provides management, maintenance, supervision, and operation of all horticultural activities managed by the agency. The goal of this service is to provide clean and healthy neighborhoods through the beautification of park properties and providing access to healthy fruits and vegetables to the community at-large. Activities performed by the service include providing operational support at the Howard Peters Rawlings Conservatory and the 200-acre Cylburn Arboretum, as well as providing approximately 700 community gardening plots throughout the city.'),
    ('SRV0651', 'This service provides a wide variety of recreational, fitness, and health promotion programs for Baltimore City’s older adults. The goal of the service is to promote healthy aging by providing opportunities for older adults to stay physically and mentally active, socially engaged, and aware of healthy lifestyle choices. Activities provided by this service include senior activities in BCRP’s recreation centers, a partnership with the Health Department’s CARE Service to provide senior recreational programming at the Cherry Hill Senior Center, and community-based golden age clubs located in churches and senior housing facilities located throughout Baltimore City.'),
    ('SRV0652', 'This service provides a wide variety of recreational opportunities and services for individuals with disabilities in both specialized and inclusive environments in accordance with federal law mandated by the Americans with Disabilities Act. The goal of this service is to provide inclusive programs that promote a healthy lifestyle through physical and emotional activities. Activities provided by this service include sports, fitness, arts and crafts, dance, outdoor and social activities, and the Special Olympics program, with special events for more than 20,000 participants each year.'),
    ('SRV0653', 'This service manages approximately 2,000 permits for special events on park property each year and coordinates volunteers, nature programs, and large Citywide events. The goal of this service is to engage with volunteers and program partners to provide a wide range of outdoor recreational and leisure opportunities through direct program management. Activities provided by this service include supporting operations for special events like AFRAM, Charm City Lights, Music in the Park, and coordinating with residents to provide equitable access for permitted events.'),
    ('SRV0654', 'This service establishes and cares for trees in the City’s road rights-of-way and on park property, including naturally forested park lands. The goal of this service is to continue improving Baltimore’s air quality through the expansion of Baltimore’s tree canopy and move the City towards a more sustainable future. Activities performed by this service include emergency tree services, planting, watering, pruning, removal, utilizing woody byproducts from tree care operations, and providing oversight on projects within the City which could impact trees, including integrated vegetation management.'),
    ('SRV0656', 'This service enforces local labor standards related to minimum wage, living wage, prevailing wage, and displaced service worker protections in Baltimore City. It is administered by the Baltimore City Wage Commission and supported by staff authorized under the City Code. The goal of this service is to promote fair labor practices by ensuring that workers employed within the City receive compensation in accordance with City Wage Laws. The activities of this service include conducting audits and investigations, reviewing payroll records, issuing enforcement actions and penalties, recommending wage rate updates to the Board of Estimates, and educating employers and workers on their rights and responsibilities under City law.'),
    ('SRV0660', 'This service provides executive leadership and administrative support for the Bureau of Solid Waste. The goal of this service is to oversee and implement daily operations through coordination and strategic planning. Activities performed by this service include oversight and planning of capital projects, budget development and fiscal operations, asset management, hiring and recruitment, communications and community partnerships, and information technology services.'),
    ('SRV0661', 'This service maintains the cleanliness of streets, sidewalks, alleys and stormwater infrastructure. The goal of this service is to improve water quality in the harbor and Bay through routine cleaning of the public right-of-way. Activities performed by this service include: street and alley cleaning, mechanical street-sweeping, business district cleaning, marine operations, and graffiti removal.'),
    ('SRV0662', 'This service ensures that vacant and unoccupied property meet certain City standards, as well as proactively combating the rodent population. The goal of this service is to ensure that vacant and unoccupied properties meet city standards. Activities conducted by this service include: cleaning and boarding vacant properties, mowing vacant lots, processing liens, and rat control services.'),
    ('SRV0663', 'This service provides household waste and recycling pick up from over 210,000 households, 290 multi-family dwellings, and commercial businesses. The goal of this program is to ensure that waste is picked up and processed weekly and routinely. The activities conducted by this service include household waste disposal, mixed refuse collection, recycling administration, bulk trash collection, condominium collections, and the municipal can program.'),
    ('SRV0664', 'This service manages nearly 700,000 tons of mixed refuse and recycling materials at the City’s landfill and the Northwest Transfer Station. The goal of this service is to ensure that all waste is processed in accordance with federal, state and local standards. Activities conducted by this service include processing of collected recyclables, landfill operations, and operation of the Northwest Transfer Station.'),
    ('SRV0670', 'This service provides executive leadership and administrative support for water, wastewater and stormwater related services. The goal of this service is to oversee and implement daily operations through coordination and strategic planning. Activities performed by this service include oversight and planning of capital projects, budget development and fiscal operations, asset management, hiring and recruitment, communications and community partnerships, and information technology services.'),
    ('SRV0671', 'This service operates the water distribution system that supplies water to 1.8 million customers in the Baltimore Metropolitan region. The goal of this service is to provide clean drinking water to all users of the system. Activities performed by this service include maintaining three watershed systems, three filtration plants, pumping stations, and over 3,800 miles of water distribution mains. The service is also responsible for watershed safety and management, water filtration and treatment, and pipe replacement.'),
    ('SRV0672', 'This service is responsible for managing water meters and utility customer billing. The goal of this service is to provide timely and accurate quarterly meter reading and billing of 412,000 water accounts. Activities performed by this service include: quarterly meter reading and billing, installing and maintaining water meters, delinquent turn offs, and utility customer service (including water assistance and discount programs).'),
    ('SRV0673', 'This service provides for wastewater collection and treatment for up to 253 million gallons/day of wastewater from 1.8 million people in the metropolitan region. The goal of this service is to collect and process wastewater to ensure clean and safe drinking water throughout the system. Activities performed by this service include operating 12 wastewater pumping stations, 1,400 miles of sewer mains and two wastewater treatment facilities.'),
    ('SRV0674', 'This service is responsible for maintaining stormwater infrastructure to protect, enhance, and restore watersheds in the City of Baltimore and Chesapeake Bay tributaries. The goal of this service is to reduce runoff that flows into the City’s watersheds. Activities performed by this service include maintaining 146 miles of storm drainpipes, 52,438 inlets, 27,561 manholes, 1,709 outfalls, four storm water pumping stations, and five debris collectors. This service is also responsible for the overall administration of the Stormwater Enterprise Fund including debt service and capital planning.'),
    ('SRV0675', 'This service overseeing capital projects for water and wastewater infrastructure. The goal of this service is to ensure that the City is creating and delivering infrastructure in a timely manner while meeting the standards set by the Federal and State government, including the federal consent decree. Activities performed by this service include engineering and planning for water/wastewater capital projects and inspecting wastewater and water facilities.'),
    ('SRV0676', 'This service provides executive leadership and administrative support for the Department of Public Works. The goal of this service is to oversee and implement daily operations through strategic coordination and planning. Service activities include oversight and planning of capital projects, budget development and fiscal operations, asset management, hiring and recruitment, communications and community partnerships, and information technology services.'),
    ('SRV0681', 'This service provides executive direction and support functions for the agency’s operating divisions, including human resources, information technology, contract administration, equal opportunity compliance, as well as fiscal services and procurement. The goal of this service is to oversee agency policy and planning functions. Activities performed by this service include program management, data collection and analysis, and public information services.'),
    ('SRV0682', 'This service manages City-owned parking facilities and meters, residential and business parking programs, and develops parking plans and management strategies. The goal of this service is to meet the parking needs of City residents and visitors. Activities performed by this service include managing 10,000 parking spaces in City-owned garages and lots; managing and maintaining 1,000 pay-by-license plate multi-space parking meters and 1,900 single space parking meters; and administering the Residential Permit Parking, Residential Reserved Disabled Parking, and Valet Regulation programs.'),
    ('SRV0683', 'This service provides the preventive maintenance, resurfacing, and streetscaping of more than 4,745 lane miles of City roadways, 3,600 miles of sidewalks, and more than 1,100 lane miles of alleys throughout the City. The goal of this service is to improve the overall condition of the City’s roadways, sidewalks, and alleys. Activities performed by this service include: in-house milling and paving teams, roadway engineering design, construction, and oversight of street improvements, and inspecting and testing City pavement.'),
    ('SRV0684', 'This service is responsible for designing, installing, maintaining, and inspecting the City’s network of 250,000 traffic control signs and devices. The goal of this service is to ensure roadways are safe for pedestrians, motorists, and bicyclists. Activities performed by this service include: conducting traffic impact studies, overseeing capital projects to upgrade traffic signals, operating the Traffic Management Center, and maintaining traffic control signs and devices.'),
    ('SRV0685', 'This service is responsible for overseeing the permitting process for outdoor special events and street vendors. Activities performed by this service include: set up for events (stages, booths, electrical equipment, etc.), installing street banners and holiday decorations in commercial areas, and overseeing the permitting process for more than 300 fairs, festivals, and other events.'),
    ('SRV0687', 'This service maintains the public right-of-way at the Inner Harbor, including the lighting, promenade, bulkhead, finger piers, and water and utility hookups. Activities performed by this service includes landscaping and maintenance for a number of fountains and public plazas, such as Hopkins Plaza, located throughout the central business district.'),
    ('SRV0688', 'This service is responsible for coordinating and carrying out snow and ice removal throughout the City. The goal of this service is to quickly and efficiently remove snow and ice to improve the safety of roadways following a snow or ice storm. Activities performed by this service include equipment preparation, deploying stuff during a weather event, and overseeing the procurement of supplies and equipment needed for removal services.'),
    ('SRV0689', 'This service oversees the process to impound and tow vehicles that are illegally parked and abandoned. Activities performed by this service includes operating the impound facilities at 6700 Pulaski Highway and 410 Fallsway as well as towing vehicles to these facilities.'),
    ('SRV0690', 'This service supports a variety of cleaner forms of transportation. The goal of this service is to reduce dependence of single occupancy vehicles. Activities performed by this service include: coordination with Maryland Transit Administration, operating the Charm City Circulator and the Harbor Connector water taxi, installing and promoting bicycle facilities, supporting emerging alternative modes such as dockless and shared vehicles, and promoting rideshare programs.'),
    ('SRV0691', 'This service maintains and mows the grass in the 870 median strips in the City roadways. The goal of this service is keeping medians clean and free of trash and debris. Activities performed by the service include: mulching and cleaning tree pits, mowing of certain City-owned lots, and removing trash and illegal signs.'),
    ('SRV0692', 'The service maintains the City’s 305 bridges. The goal of this service is to ensure safe and timely passage of motorists, pedestrians, and bicyclists over roads, waterways, parks, and railroads. Activities performed by this service include: performing the federally mandated biennial bridge inspection, and overseeing maintenance and capital projects on the City’s bridges.'),
    ('SRV0693', 'This service is responsible for enforcing parking laws throughout the City. The goal of this service is to improve public safety, promote commercial activity, and ensure smooth traffic flow. Activities performed by this service include: conducting routine parking enforcement throughout the City and coordinating impounding abandoned vehicles.'),
    ('SRV0694', 'This service provides for a system of accurate survey points used by civil engineers, land title agents, developers, and others preparing roadway and bridge designs, residential and commercial development projects, and sale and acquisition of property for municipal use. The goal of this service includes three specific functions: maintaining the City’s Horizontal and Vertical Survey Controls, reviewing plats prepared by private consultants, and preparing plats and ordinances for 
review and approval by the Mayor and City Council.'),
    ('SRV0695', 'This service coordinates dockside activities and the docking of vessels within the Inner Harbor. The goal of this service is to support the smooth flow of traffic through the Inner Harbor and ensure compliance with docking fees. Activities performed by this service include: collecting docking fees from transient pleasure boats, scheduling docking for charter boats, cruise ships and special ship visits, as well as promoting the City’s dock availability to tourists.'),
    ('SRV0696', 'This service inspects and monitors street cuts in the City’s rights-of-way. The goal of this service is to minimize the number of street cuts. Activities performed by this service include: managing the software systems used to monitor street projects; coordinating project schedules with other agencies, utility companies, and contractors that perform street cuts.'),
    ('SRV0697', 'This service is responsible for coordinating all programs focused on improving traffic and pedestrian safety. The goal of this service is to reduce injuries and accidents involving pedestrians. Activities performed by the service include: deploying crossing guards at elementary and middle schools, operating Safety City initiatives for raising awareness of children about traffic and pedestrian safety, fabricating and installing traffic signs, and overseeing the red light and speed 
camera programs.'),
    ('SRV0698', 'This service is responsible for the overall fiscal strategy and fiscal management of the City. The goal of this service includes overseeing the City Budget process and holding the internal Bureaus - Budget and Management Research, Revenue Collections, Procurement, Accounting, Payroll Services, Treasury Management, and the Office of Risk Management - accountable for their performance. Activities performed by this service include coordinating all human capital management activities within the department; performing management analysis; and executing initiatives with other City agencies to improve the efficiency and effectiveness of government.'),
    ('SRV0699', 'This service is responsible for supporting City agencies to purchase the goods and services which make possible the government’s operations and capital improvements. The primary activity of the Bureau of Procurement (BOP) is to facilitate efficient, timely and effective sourcing and purchasing practices, for goods and services, in-line with City Charter requirements.'),
    ('SRV0700', 'This service is responsible for providing a process for City agencies to dispose of surplus property. The goal of this service is to provide a streamlined process for disposing property which is being replaced or is no longer useful. The primary activity performed by this service is facilitating the disposition and acquisition process for surplus property.'),
    ('SRV0701', 'This service is responsible for operating the Print Shop - the City’s central printing service. The goal of this service is to provide professional printing services for City agencies. Activities performed by this service include professional graphic design, printing, copying, document scanning, data center printing, and forms distribution.'),
    ('SRV0703', 'This service is responsible for paying ~14,000 full-time employees as well as seasonal youth employees including ~6,000 Youth Works employees. The goal of this service is to ensure that proper internal controls exist over the payroll process. Activities performed by this service include processing special paychecks, coordinating quarterly payroll tax reporting, managing garnishment processing, reconciling payroll bank accounts, all payroll related special projects including sick and safe leave, check disbursement to the State of Maryland, and coordinating year-end processing of W-2s.'),
    ('SRV0704', 'This service provides accounting and reporting services for the City of Baltimore, including preparation of the Annual Comprehensive Financial Report (ACFR). The goal of this service is to ensure the City’s financial activities are executed and reported in accordance with Generally Accepted accounting Principles (GAAP). Activities performed by this service include grant accounting, capital accounting, financial accounting, and accounts receivable.'),
    ('SRV0707', 'This service is responsible for overseeing the City’s worker compensation and self-insurance programs. The goal of this service is to provide training, policies, and resources to create safe workspaces to avoid accidents and injuries.'),
    ('SRV0708', 'This service provides for the management of the City’s annual operating budget. Key activities performed by the service include: overseeing the development and monitoring of the City’s operating budget, forecasting and monitoring all General Fund revenues, preparing fiscal analysis of proposed City and State legislation, and performing management research regarding the efficiency and effectiveness of City services. The goal of this service is to provide quality, thorough, and accurate analysis to City policymakers to help inform budget and financial decisions.'),
    ('SRV0710', 'This service is responsible for overseeing the City’s tax credits and representing the City in assessment appeals. The goal of this service is to identify and eliminate inefficiencies and prevent fraud in tax credits. Activities performed by this service include: assessment appeals, Historic Tax Credit appraisal reviews, PILOT records management, and managing real property tax credits.'),
    ('SRV0711', 'This service is responsible for coordinating, designing, and implementing all software system used by the Department of Finance. The goal of this service is to ensure the software systems needed to operate the department are functioning properly and meeting the City’s business needs. Activities performed by the service include: coordinating training and reporting for the City’s ERP (Workday), and supporting the implementation of new software systems.'),
    ('SRV0715', 'This service provides departmental leadership, facilitates and guides the agency’s delivery of services, and ensures agency compliance with city, state, and federal laws, procedures, and standards. The goal of this service is to improve administrative processes, standardize operating procedures and systems. Activities performed by this service include providing the department with executive leadership, fiscal services, human resources management, facilities & materials management, information systems support, and grants capacity development.'),
    ('SRV0716', 'This service enforces all codes, rules and regulations to improve the health and safety of residents and the animal population. The goal of this service is to protect residents from zoonotic diseases and animal attacks, and the animal population from neglect, abuse, and cruel treatment. Activities performed by this service include the Baltimore Animal Rescue and Care Shelter (BARCS), which provides animal shelter services - including housing and care - for lost and found animals, pet licenses, adoptions, volunteers, fosters, animal rescue, and low-cost vaccination and microchip clinics.'),
    ('SRV0717', 'This service licenses and inspects food facilities, schools, swimming pools, institutional facilities, and tattoo operations to ensure that health and safety requirements are met. The goal of this service is to protect public health by conducting inspections to ensure compliance with State and local health codes. Activities performed by this service include Food Control, Ecology and Institutional Services, and the Plan Review Program. Environmental Inspection Services investigates environmental nuisances and potential hazards such as odor, noise, mosquitoes, sewage spills, and food borne, vector borne, and water borne illnesses.'),
    ('SRV0718', 'This service focuses on specific efforts aimed at reducing the development and severity of chronic diseases and other morbidities. The goal of this service is to engage and empower individuals and communities to choose healthy behaviors, and make changes that reduce the risk of developing chronic diseases and other morbidities. Activities performed by this service include Tobacco-Free Baltimore (Tobacco Enforcement, Tobacco Prevention Education, and Cessation); Baltimarket (Virtual Supermarket and Nutrition Education); Diabetes Coalition; and The Baltimore City Tobacco and Cancer Coalition.'),
    ('SRV0720', 'This service provides preventative and care services for people who are uninsured or under-insured. The goal of this service is to provide access to care for people living with HIV who are uninsured or under-insured and to close access-tocare gaps to enhance health outcomes and quality of life of persons who are HIV-positive. Activities performed by this service include medical and supportive services, including oral health, case management services, medical transportation services, emergency financial assistance, and housing services. This service also houses the Ryan White Program which provides comprehensive treatment services to HIV-positive people.'),
    ('SRV0721', 'This service manages and/or funds 13 senior centers in the City. The goal of this service is to provide adults aged 55 and older, persons with disabilities and caregivers the opportunity to remain healthy and active in their communities while aging with dignity. Activities performed by this service include supporting enhanced health promotion and education programs, continuing provision of congregate meals, and distribution of Senior Farmers Market Nutrition program checks.'),
    ('SRV0723', 'This service provides advocacy, information and referral, benefits guidance and volunteer services to older adults, their families, caregivers, and adults with disabilities. The goal of this service is to help older adults and their families access resources, offer opportunities for older adults to engage in their communities through meaningful volunteerism, and to protect the rights of older adults living in long-term care facilities. Activities performed by this service include screening; linkage to information and resources through Maryland Access Point (MAP); referral; counseling; complaint investigation for nursing homes and assisted living facilities; application assistance; benefit enrollment; and volunteer services.'),
    ('SRV0724', 'This service provides support and/or direct care to Medicaid-eligible, cognitively impaired, disabled and/or chronically ill adults who reside in their own homes, assisted living facilities and/or institutional settings. The goal of this service is to mitigate the impacts of chronic health conditions affecting older adults. Activities performed by this service include inhome services, subsidized assisted living care, guardianship case management, and volunteer visiting programs for isolated elderly.'),
    ('SRV0725', 'This service supports older adults and their caregivers with programs addressing core needs including nutrition, transportation and health education and promotion. The goal of this service is to provide older adult residents with supplemental food delivery and transportation services. Activities performed by this service include congregate and home-delivered programs, support for the subsidized taxi voucher (Taxi Card) program, and instituting more mechanisms for customer feedback and quality improvement.'),
    ('SRV0726', 'This service provides executive direction, communications & public relations, fiscal management, human capital management, and performance management for the Department. The goal of this service is to drive innovation in the delivery of these services and to promote the agency''s strategic plan which includes driving operational success through expertise, accountability, and effective use of data; to attract, train, and retain talented people; to strengthen service excellence. Activities performed by this service include administrative direction, fiscal management, human resource support, performance management, communications, and change management.'),
    ('SRV0727', 'This service is responsible for analyzing and approving all construction activities within the City right-of-way. The goal of this service is to ensure these projects are carried out in alignment with the City’s charter and code. Key activities performed by the service include: maintaining the real property maps, plats and property identification database for the City’s 234,000 properties, reviewing construction projects for new City infrastructure and connecting to existing utilities, opening and closing City streets and alleys,  creating utility easements on private property, and right-of-way infrastructure coordination.'),
    ('SRV0730', 'This service oversees energy utility accounts management for City agencies, implementation of energy efficiency & renewable energy projects, and tracking progress towards the City’s municipal energy use and greenhouse gas reduction goals consistent with the City’s Sustainability Plan and State mandates. The goal of this service is to move the City and its residents towards a more sustainable future and zero waste. Activities performed by this service include managing citywide accounts and billing for energy costs, overseeing energy efficiency investments, and serving as the City’s subject matter experts on energy policy and strategy.'),
    ('SRV0731', 'This service directly manages over 60 municipal facilities and maintains the portfolio of over 500 Mayor and City Council owned properties. The goal of this service is to maintain facilities in a data driven manner that improves operations and reduce expenditures by embracing preventative maintenance and proactive measures. Activities performed by this service include repair of city facilities, custodial services, building security, and general maintenance. This service utilizes a modern, centralized data system to improve operational efficiency, data quality, and public transparency.'),
    ('SRV0734', 'This service is responsible for the planning, design, construction, and delivery of capital projects to the majority of City owned facilities. This service is comprised of three major sections: (1) Architectural & Engineering Design, (2) Construction Management, and (3) Contract Administration. The goal of the service is to deliver capital projects on-time and at-budget. Activities performed by this service include project management support for capital projects from inception to completion. The personnel costs for this service are funded through capital projects.'),
    ('SRV0737', 'This service provides leadership and support to the Department’s five operational Divisions. The goal of this service is to provide each division with tools, resources, and direction to drive the Department’s mission. Activities performed by this service include: Budget and Accounting, Human Resources, Facilities Management, Communications, and Information Technology.'),
    ('SRV0738', 'This service provides energy efficient home upgrades to low-income residents of Baltimore City, an instrumental part of the Comprehensive Vacants Reduction & Prevention Strategy. The goal of this service is to reduce homeowner energy costs, redirect money into the economy, and expand the market for workers in skilled and sustainable trades. Activities performed by this service include aiding residents with energy, health, and safety upgrades, which enables them to maintain their properties and prevent the increase of new vacant homes.'),
    ('SRV0741', 'This service operates five neighborhood Community Action Partnership (CAP) centers. The goal of this service is to connect residents with access to a host of services including billing assistance, security deposit assistance, financial literacy resources, and food and nutrition workshops. Activities performed by this service include: administering the City’s Water4All program, staffing and operating the 5 CAP centers, and partnering with agencies that offer various assistance programs.'),
    ('SRV0742', 'This service provides grants and incentives to Baltimore City homebuyers. This goal of the service is to promote neighborhood stability and enable prospective homebuyers to achieve the dream of homeownership. Activities performed by this service include assistance to new homebuyers with down payments, home inspection costs, and settlement expenses, as well as provision of classes, seminars, counseling, and referrals for current homeowners to prevent foreclosure.'),
    ('SRV0745', 'This service is responsible for ensuring compliance with Baltimore’s housing and property maintenance codes. The goal of this service is to maintain safe, clean and attractive neighborhoods throughout Baltimore. Activities performed by this service include housing inspections across the entire city and issuing the appropriate violations and citations, including vacant building notices, when properties are not in compliance with the codes.'),
    ('SRV0747', 'This service oversees the licensing of rental dwellings and the registration of non-owner-occupied dwelling units and vacant properties. The goal of this service is to ensure current contact information for various code enforcement purposes, including leveraging compliance with both State and local law, as well as ensuring rental dwellings meet minimum fire and safety standards and compliance with State lead paint reporting requirements. Activities performed by this service include: registering burglar alarm users, contractors and monitoring companies, billing users in certain circumstances for false alarms; and, registering of electricians, demolition contractors, plumbers and HVAC trades people, onsite utility contractors, and gas‐fitters.'),
    ('SRV0748', 'This service promotes the creation and preservation of affordable housing in Baltimore City through management of the Affordable Housing Trust Fund (AHTF). The goal of this service is to increase access to affordable homeownership and rental housing opportunities for residents. Activities performed by this service include creation of mixed-income housing opportunities and direct financing to developers through the federal HOME and CDBG programs, the AHTF, and other sources.'),
    ('SRV0749', 'This service oversees the sale and acquisition of property used for revitalization. The goal of this service is to support neighborhood revitalization and mixed-income community development through the implementation of the Comprehensive Vacants Reduction & Prevention Strategy. Activities performed by this service include community engagement and implementation of neighborhood led planning for development, acquisition of blighted property and assembling parcels for strategic development, maintenance of the City’s inventory, and relocation of residents displaced by strategic development projects, and the sale of City-owned properties.'),
    ('SRV0750', 'This service provides a range of forgivable, deferred, and below‐market interest rate housing rehabilitation loans to low and moderate-income households. The goal of this service is to fund home improvements necessary to address serious health, safety, and code issues. Activities performed by this service include loan provision, implementation of energy saving measures and disability accessibility modifications, and lead abatement services to reduce instances of lead poisoning in children.'),
    ('SRV0751', 'This service processes permit applications, conducts building inspections, oversees demolitions, issues all notices and citations and legal compliance to hold violators accountable. The goals of this service are to ensure the safety and integrity of new construction and alterations through monitoring construction activity, and to ensure compliance with all building and housing codes through legal action. Activities performed by this service include conducting plan review meetings with applicants, serving as a portal on behalf of other agencies for plans review, issuing permits, mailing notices and citations, as well as taking legal action against nuisance properties and receivership of vacant properties.'),
    ('SRV0752', 'This service serves as the single point of entry for housing resource requests from residents. The goal of this service is to provide human-centered services and supportive resources to individuals and families in need of home repair, at risk of losing their house, and navigating other housing related crises. Activities performed by this service include processing home repair applications, case management, landlord-tenant mediations, temporary relocation following fires, and assisting residents with delinquent mortgages, rent, property taxes and water bills.'),
    ('SRV0754', 'This service provides summer meals five days a week for children age 18 years or younger at eligible feeding sites, though funding from the Maryland State Department of Education (MSDE). The goal of this service is to build stronger, healthier and better-educated children. Activities performed by this service include provision of nutritious meals to children participating in enrichment activities.'),
    ('SRV0757', 'This service is responsible for managing the City’s Closed-Circuit Television (CCTV) network of approximately 700 cameras. The goal of this service is to help support the City’s public safety goals by providing access to camera footage throughout the City. Activities performed by this service include collaborating with internal and external stakeholders to maintain and expand the program; installing new cameras and upgrading existing cameras; and supporting end user needs.'),
    ('SRV0761', 'This service provides direct support to applicants who wish to build and invest in Baltimore City. The goal of this service is to facilitate the design review process to help support economic growth and subsequent growth in the City’s tax base. Activities performed by this service include oversight by the Planning Commission to prepare and update plans for physical development of the City, recommend projects for the capital budget, and review proposals related to the subdivision of land and amendments to the City’s Zoning Ordinance through public meetings. This work provides residents and businesses with technical assistance and professional advice on how best to achieve development goals for their property while conforming with zoning and land use regulations and meeting City Comprehensive Plan objectives.'),
    ('SRV0762', 'This service leads the City’s neighborhood-based planning initiatives from the small neighborhood plan to multi-year citywide comprehensive plans using data analysis, geographic information systems, research, and community engagement. The goal of this service is to build community capacity and promote collaboration to improve the quality of life for City residents. Activities performed by this service include drafting policy statements, analyzing legislation, conducting community outreach, building capacity and partnerships, developing housing and community development strategies, drafting comprehensive rezoning, supporting implementation of the Baltimore Green Network Plan, and developing the six-year Capital Improvement Plan.'),
    ('SRV0763', 'This service leads the City’s neighborhood-based planning initiatives from the small neighborhood plan to multi-year citywide comprehensive plans using data analysis, geographic information systems, research, and community engagement. The goal of this service is to build community capacity and promote collaboration to improve the quality of life for City residents. Activities performed by this service include drafting policy statements, analyzing legislation, conducting community outreach, building capacity and partnerships, developing housing and community development strategies, drafting comprehensive rezoning, supporting implementation of the Baltimore Green Network Plan, and developing the six-year Capital Improvement Plan.'),
    ('SRV0765', 'This service funds the Baltimore Office of Sustainability (BOS), which is guided by the Baltimore Sustainability Plan. The goal of this service is to implement the Sustainability Plan, which lays out a broad, inclusive, and community-responsive sustainability agenda. Activities performed by this service include overseeing environmental regulations, and completing FEMA and MEMA disaster planning.'),
    ('SRV0768', 'This service provides executive leadership and administrative support for the Planning Department. The goal of this service is to advise the Mayor, senior staff, other cabinet agencies, and the Planning, Preservation and Sustainability Commissions on issues and policies related to development, land use, zoning, capital programming, sustainability, and historic preservation. Activities performed by this service include budget planning and fiscal operations, human resources, and general administrative services for the Planning Department.'),
    ('SRV0770', 'This service is responsible for the agency’s overall strategy, performance, and management while also overseeing citywide HR policies. This service partners with the Schaefer Center and University of Baltimore''s Certified Public Manager (CPM) program to develop local leadership talent within the City''s high achieving workforce. The goal of this service is to ensure human resource services, policies, procedures, and systems support the City’s business needs and are properly aligned with the City’s aim to be an employer of choice. Activities performed by this service include fiscal oversight, employment policy development and implementation, employment law and regulatory compliance, strategy development and communications, employee engagement, Civil Service Commission administration and rule-making, and Human Resource Information Systems (HRIS) operations.'),
    ('SRV0771', 'This service is responsible for administering the City’s health and welfare benefits for all active employees, retirees, and their dependents according to the terms and conditions of the City’s contracts covering medical plans, dental plans, life insurance, prescription drug plans, vision, flexible spending accounts, and unemployment insurance. This service also administers the citywide Health and Wellness initiatives through the Employee Assistance Program. The goal of this service is to serve as a liaison between members and contracted carriers to provide benefits to the City, while providing high quality health benefits options to employees and retirees. Activities performed by this service also include facilitating annual open enrollment and managing health benefits plans, providing mental health and wellness services, and administering the Employee Assistance Program (EAP).'),
    ('SRV0772', 'This service includes the offices of Classification and Compensation as well as Shared Services and Recruitment. The Office of Classification and Compensation is responsible for classifying occupational groups, developing job specifications, and establishing compensation levels for positions that comprise Baltimore City’s workforce. The Office of Shared Services and Recruitment provides HR guidance and support to agencies without in-house HR support. The Recruitment Team standardizes the administrative lifecycle for position requisitions and candidate selection criteria. The goal of this service is to provide centralized human resources for City agencies by creating and implementing a multi-year workforce retention plan to ensure continuity of service delivery and intentional transition'),
    ('SRV0773', 'This service offers learning and development opportunities for City agencies to meet both personal and professional growth for City employees. The goal of this service is to provide quality learning opportunities that meet the needs of the City’s diverse workforce and support the mayoral initiatives. Activities performed by this service include proactive training initiatives such as recurring instructor-led sessions, maintaining and growing a library with over 3,500 on-demand courses, and curating learning programs. The service also supports reactive training in City agencies by identifying and addressing skill gaps through root cause analysis and implementing customized training plans to address those gaps.'),
    ('SRV0781', 'The service provides administrative oversight to the State Attorney’s Office (SAO). The goal of this service is to ensure the efficient functioning of the State Attorney’s Office by managing financial and personnel matters.  Activities performed by this service include forecasting, monitoring and managing expenditures; human resource management; developing, 
supporting and implementing policy and legislation to more effectively prosecute crime; coordinating intra-agency 
partnerships, projects, and initiatives; maintaining and improving information systems to support all of the office’s 
initiatives, and supporting the personnel and technology needs relating to body worn camera video review.'),
    ('SRV0786', 'This service supports full-time personnel who assist victims and witnesses of crime. The goal of this service is to provide 
counseling and guidance, notification of rights and support in court, and oversee monetary support and reimbursement 
for assisting law enforcement. Activities performed by this service include assisting witnesses of crime determined to be 
at risk of intimidation or retribution by providing relocation assistance (temporary and permanent new housing) and other 
limited forms of financial support, including vouchers for food and travel expenses.'),
    ('SRV0788', 'This service is responsible for operating the City’s public library system and the State Library Resource Center for the State of Maryland. The goal of this service is to provide equitable access to information at no cost to residents. The Enoch Pratt Free Library operates 21 neighborhood libraries, the Central Library, the State Library Resource Center, two bookmobiles, and a mobile jobs vehicle. Key activities performed by the service include: homework support, information referral and reference services (in-person and virtually), assisting with access to research and database materials, providing family literacy services, providing job career and computer training programs, and providing broadband access. The Library provides community space for a variety of programming at the Central Library and branch locations.'),
    ('SRV0791', 'This service, in partnership with City Schools, provides an alternative education model for youth unsuccessful in a traditional school setting through the operation of the Youth Opportunity (YO) Academy, and as part of the Blueprint for Maryland’s Future Initiative, embeds career coaches within middle and high schools to guide students in career development. The goal for YO Academy is for youth to learn at their own pace and earn the credits necessary for graduation or to transition back to their zoned high school; the goals for Blueprint are to provide mentorship and connect students to work-based learning opportunities, ensuring they are prepared for both academic success and future employment. Key activities performed by this service include providing job readiness and career exploration activities and access to resources that support personal development and skill-building.'),
    ('SRV0792', 'This service provides a suite of employment and education services for City residents. The goal of this service is to connect participants to career pathways through employment and occupational training. Activities performed by this service include case management, job preparation and placement, career counseling, and skill building as well as postemployment activities, such as help with retention and non-traditional work hours.'),
    ('SRV0793', 'This service operates Community Job Hubs and provides a full range of workforce services.  The goal of this service is to provide opportunities to job seeking residents to build career portfolios, obtain essential computer skills, and learn occupational skills tied directly to Baltimore''s high-growth sectors. Activities performed by this service include job readiness training, resume assistance, interview preparation, career navigation, career exploration, employment placement services, and referral to occupational training and support services. Specific programs include Train Up (free occupational training in high-demand fields) and Let’s Ride to Work (free rideshare services for newly employed residents).'),
    ('SRV0794', 'This service provides administrative oversight to the Mayor’s Office of Employment Development (MOED). The goal of this service is to support programs and initiatives that provide economic opportunity to Baltimore residents. Activities performed by this service include advocating for the resources and support needed to make programs successful, including helping to promote programs and raise awareness, and providing financial resources, staffing, training, and other support services. The service also administers the Baltimore City Local Hiring Law, which supports continued economic recovery by expanding job opportunities for City residents.'),
    ('SRV0795', 'This service provides City residents with access to workforce services at two comprehensive one-stop centers supported by federal Workforce Innovation and Opportunity Act (WIOA) and City funds. The goal of this service is to prepare residents for job interviews, learn about occupational skills training, and connect to employers seeking workers. Activities performed by this service include readiness training, resume assistance, interview preparation, career navigation, and career exploration, along with employment placement services and referrals to occupational training and other support services, such as behavioral health support.'),
    ('SRV0796', 'This service offers a broad range of services to assist returning citizens in successfully transitioning to work, home, and community. The goal of this service is to support a smooth transition from incarceration into employment for returning residents. Activities performed by this service include career counseling, job readiness, skills training, and job search and retention assistance.'),
    ('SRV0797', 'This service provides out-of-school youth and unemployed young adults access to a full range of educational, occupational, and personal support services in a "one-stop" safe and nurturing environment. The goal of this service is to increase the number of diplomas earned and resulting transitions to post-secondary education, military, or job corps programs by youth participants. Activities performed by this service include building participants’ academic skills, providing training for careers, and providing individualized guidance from adult members at one fully equipped Youth Opportunity (YO) Center.'),
    ('SRV0798', 'This service provides work experiences to thousands of Baltimore''s youth through a five week summer program and year-round opportunities. The goal of this service is to provide youth participants with career options and teach them work and life skills that will prepare them for future employment. Activities performed by this service include providing job opportunity to Baltimore City young people by connected eligible participants with Host Employers that are made up of nonprofits, government agencies, emerging businesses and Hire Employers mainly consisting of medium-large businesses that pay out of pocket.'),
    ('SRV0800', 'This service is supported by the federal Workforce Innovation and Opportunity Act (WIOA) to award funds to community-based organizations to offer occupational skills training opportunities. The goal of this service is to prepare economically disadvantaged youth ages 18-24 to achieve major educational and skill development. Activities performed by this service include offering industry-recognized credentials, case management, and job placement assistance that leverages strong employer relationships. The service will also award funding to providers to assist those in-school youth in their senior year with securing their high school diplomas, either by keeping them engaged in high school through graduation or through alternative education that leads to a high school diploma.'),
    ('SRV0802', 'This service provides and directs the resources needed for successful and effective IT deployment within the City. The goal of this service is to provide operational support to ensure that BCIT’s strategy, goals and initiatives are successfully implemented. Activities performed by this service include human resources, fiscal services, project management, facilities, and change management functions.'),
    ('SRV0803', 'This service upgrades and modernizes IT systems utilizing technical expertise to optimize system efficiency. The goal of this service is to enable BCIT to deliver services and solutions to support citywide and agency-specific operations. Activities performed by this service include: application development and maintenance; agency IT service optimization and portfolio management; data access and analysis; website and SharePoint administration; Geographic Information System (GIS) mapping; mainframe system support; and enterprise-wide software application support.'),
    ('SRV0804', 'This service manages the City’s 311 call center, which is residents’ “One Call to City Hall” to request services, get general information and answer non-emergency questions, diverting non-emergency calls from 911. The goal of this service is to provide universal, standardized, inter-agency call intake and work order management through the Customer Service Request (CSR) system. Activities performed by this service include development, implementation, and continuing support of the CSR System and gathering information from 311 to allow all City agencies to access and measure customer responsiveness and satisfaction.'),
    ('SRV0805', 'This service is responsible for coordinating and supporting the management and maintenance of the City’s enterprise IT infrastructure services, information security and public safety technologies for the City of Baltimore; providing customer support to City employees through the help and service desks; and meeting the hardware and software needs of City agencies. The goals of this service include building a cybersecurity governance framework; implementing a cloud-based data center; improving the security and resilience of the network’s infrastructure; and enhancing the reliability and availability of public safety technology. The key activities of this service include the 800MHz Land-Mobile Radio (LMR) system, Computer Aided Dispatch (CAD) system, E9-1-1 telephony, City fiber management and installation, cyber security policy and threat mitigation, Identity Account Management (IdAM), network and systems engineering, the Bmore IT Service Desk, end-user support and engineering, as well as the PC Refresh Program.'),
    ('SRV0807', 'This service is responsible for  implementation and compliance of the Federal Consent Decree through education, training, and monitoring. The goal of this service is to improve policies and training, overhaul antiquated technology, and create accountability systems to provide better services to the community fairly and equitably. Activities performed by this service include soliciting input from community members regarding operational policy, training development, and police-community relations.'),
    ('SRV0809', 'This service focuses on increasing jobs in Baltimore’s key growth sectors. The goal of this service is to promote investment in Baltimore City and provide significant financial benefit to Baltimore and the State of Maryland. Activities performed by this service include expanding companies located in and investing in Baltimore, and fostering opportunities for small, women-owned, and minority-owned business participation.'),
    ('SRV0810', 'This service serves as the single-point-of-contact resource for anyone interested in major real estate development projects. The goal of this service is to promote real estate development within Baltimore City. Activities performed by this service include include strategic planning, development assistance, expedition of building permits and other approvals, negotiation of the sale or lease of City-owned properties, and management of urban renewal areas and Business Parks.'),
    ('SRV0811', 'This service is provided through a non-profit organization managing the City’s Waterfront Management special benefits district. The goal of this service is to create an attractive Inner Harbor for residents and tourists by maintaining an active, clean, and beautiful Inner Harbor. Activities performed by this service include coordination of day-to-day clean, green, and safety operations, and the planning and implementation of both economic and physical development of the Inner Harbor.'),
    ('SRV0813', 'This service provides support to entrepreneurs and small businesses through technical assistance and resources, including the Made in Baltimore and Emerging Technology Center (ETC) programs. The goal of this service is to support Baltimore entrepreneurs in launching successful businesses generally focused on two industry growth sectors: technology and manufacturing. Activities performed by this service include provision of affordable office and retail space, online marketing and sales platforms, and access to professional consultants and networking events.'),
    ('SRV0815', 'This service promotes living in Baltimore City. The goal of this service is to grow Baltimore City’s population in order to create and sustain an equitable and thriving local economy. Activities performed by this service include assisting current and prospective residents with City living resources; marketing City neighborhoods as great places to live; hosting residential neighborhood tours; supporting residents with children in their decisions to stay in the City; collaborating with employers on Live Near Your Work programs and other recruitment efforts; and educating homebuyers and real estate professionals on the City''s down payment assistance programs, tax credits, and other incentives.'),
    ('SRV0816', 'This service is responsible for supporting Patrol districts by responding to critical calls and incidents that require specialized expertise, training, and resources. The goal of this service is to provide specialized personnel to high visibility areas in tandem with the Patrol Districts when areas experience increases in violent crime. Activities supported by this service include the Special Weapons and Tactics (SWAT) Unit, Aviation Unit, and the K-9 Unit.'),
    ('SRV0817', 'This service presides over probate, estate, and guardianship cases. The goal of this service is to protect the rights of minors and determine the best placement options when necessary. The key activities performed by this service include: handling cases involving wills or estates for deceased individuals, presiding over guardianship cases, and providing advice to parties seeking guidance in probate and guardianship matters.'),
    ('SRV0820', 'This service, which includes Visit Baltimore, promotes Baltimore as the preferred tourist and convention destination for visitors and organizations. The goal of this service is to attract visitors and groups to the City, with 40% of the hotel taxes dedicated to Visit Baltimore as stipulated by State law. Activities performed by Visit Baltimore, the official destination marketing organization of Baltimore, include marketing Baltimore attractions, as well as soliciting group business for meetings and conventions at the Baltimore Convention Center.'),
    ('SRV0824', 'This service provides funding for Create Baltimore, formerly the Baltimore Office of Promotion & the Arts (BOPA), which serves as Baltimore’s arts council, events center, and film office. The goals of this service are to provide support for artists and arts organizations, to generate economic impact annually for the City of Baltimore, and bolster Baltimore’s image as an attractive place to live, work, and play. Activities performed by this service include the production of events and festivals, administration of grants, management of arts education and public art programs, provision of film production support, and oversight of cultural facilities.'),
    ('SRV0828', 'This service provides funding for utility and maintenance costs related to the Emerson Bromo Seltzer Tower, a historic landmark which was transformed into a community arts center in 2006. The goal of this service is to open its doors to the community as a place where creativity is celebrated and shared. Activities performed by this service include rental of artistic studio space, booking of Baltimore-based artists in quarterly exhibitions, and the maintenance and promotion of a historic landmark of Baltimore City.'),
    ('SRV0833', 'N/a - no service description for this agency'),
    ('SRV0834', 'This service is responsible for certification of Minority Business Enterprises (MBEs) and Women Business Enterprises 
(WBEs). The goal of this service is to support the various needs of small and minority businesses in Baltimore City, and to ensure equitable rights and opportunities for small and minority businesses. Key activities performed by this service 
include maintaining a directory of certified businesses, investigating alleged violations of the MWBE ordinance, 
maintaining statistics on availability and utilization of MBEs and WBEs, setting annual participation goals, setting contract participation goals on a contract-by-contract basis, setting participation goals on City-assisted projects, provision of assistance to bidders and developers in identifying MBE/WBE firms, and support to the business community by 
conducting outreach, advocacy, and training.'),
    ('SRV0836', 'This service investigates allegations of misconduct by City of Baltimore employees and contractors, which may involve violations of criminal law, civil statutes, City of Baltimore regulations, or employee standards of conduct. The goal of this service is to detect instances of fraud, wasteful practices, and misuse by vendors and businesses engaged with or aspiring to work with the City, as well as individuals, groups, and businesses receiving City benefits. Activities performed by this service include independent reviews and investigations, assisting the Baltimore City Board of Ethics by examining ethics complaints, raising awareness about ethical regulations, and addressing ethics-related inquiries from City personnel, employees, and residents.'),
    ('SRV0844', 'This service supports the City’s commitment to equity, accessibility, and inclusion, housing four key commissions and programs under Article 1 of the Baltimore City Code: the Baltimore City Commission for Women, the Mayor’s Commission on Disabilities, the Equity Assessment Program, and the Baltimore City Veterans Commission. The goal of this service is to promote inclusive policies, eliminate disparities, and ensure equal access to opportunities and services for women, people with disabilities, veterans, and historically marginalized communities. Activities performed by this service include conducting equity assessments of City policies and budgets, advising City leadership on issues impacting protected populations, facilitating community engagement and education, supporting the development of inclusive programs and legislation, and assisting residents with navigating City and partner resources related to accessibility, veterans'' services, and gender equity.'),
    ('SRV0846', 'This service enforces federal, state, and local anti-discrimination laws. The goal of this service is to eliminate discrimination in all areas of community life. Activities performed by this service include investigating and resolving complaints of alleged discrimination, educating the public on anti-discrimination laws, and promoting civil rights.'),
    ('SRV0848', 'No service description; this service was abolished in a previous budget cycle.'),
    ('SRV0849', 'This service is responsible for staffing and administering the Police Accountability Board (PAB) and the Administrative Charging Committee (ACC). The goal of this service is to foster transparent and accountable practices within law enforcement agencies in Baltimore City. Activities performed by this service include investigating complaints, making policy recommendations and public reports, as well as establishing community engagement initiatives.'),
    ('SRV0850', 'This service oversees the issuance, transference, and renewal of the City’s alcoholic beverage and adult entertainment licenses. The goal of this service is to collaborate with applicants, licensees, and communities to ensure the equitable issuance of licenses. This service’s activities include holding public hearings, public engagement, issuance, transference and renewal of the City’s alcoholic beverage and adult entertainment licenses.'),
    ('SRV0851', 'This service conducts regular inspection of licensed establishments to ensure compliance with the State laws and regulations regarding the sale and service of alcohol within Baltimore City. The goal of this service is to ensure that establishments operating in Baltimore City follow state and local liquor and adult entertainment laws. Activities performed by this service include conducting routine and special investigations, holding public hearings for violations, and organizing public hearings and public engagement regarding licenses.'),
    ('SRV0853', 'This service was abolished for FY27.
This service previously acted as the Department’s liaison with Citywide partners concerning specialized public safety needs. The goal of this service was to manage and support all City issued permits and promote inclusivity in community engagement while staying adaptable to the needs of event organizers and officers. Activities performed by this service included managing the police personnel needs for Special Events, staffing Juvenile Booking, and secondary employment.'),
    ('SRV0855', 'This service manages the operations of the Baltimore Convention Center, which provides spaces and support services for local and national organizations to host meetings, trade shows, conventions, and other functions in Baltimore. The goals of this service are to generate a positive economic impact on the City, create jobs, and serve the community. Activities performed by this service include maintaining and upgrading the Convention Center facilities, hosting and supporting events, and promoting the City to convention visitors.'),
    ('SRV0857', 'N/a - no service description'),
    ('SRV0860', 'This service provides overall direction and control of the Law Department. The goal of this service is to provide sound legal advice and representation for the City of Baltimore, Mayor and City Council. Activities performed by this service include successfully defending lawsuits against the City; advocating for the City’s interest before State and Federal public bodies; drafting, negotiating and reviewing contracts and proposed laws; and advising all City government actors.'),
    ('SRV0861', 'This service provides the general litigation, labor and employment, land use, collections, and pre-litigation claims investigation services for the City. The goal of this service is to steadily increase City revenue streams while avoiding or limiting liability payouts. Activities performed by this service include defending the City and its employees from frivolous and/or exaggerated lawsuits, settling those lawsuits which are meritorious so aggrieved citizens may be compensated fairly for damages or injuries sustained; offering pro-active legal advisory and counsel work to advance operational change where needed to prevent future lawsuits.'),
    ('SRV0862', 'This service provides Charter mandated legal services essential for City operations and governance. The goal of this service is to provide advice for the City’s real estate, economic development, lending, and municipal finance activities. Activities performed by this service include negotiating, drafting, and reviewing all City contracts, and advises the Mayor’s Office, the City Council, and all City agencies, boards and commissions on the entire range of legal issues facing the City.'),
    ('SRV0869', 'This Service is no longer provided. Its permanently closed'),
    ('SRV0871', 'This service provides legal advice and counsel, and also handles all legal matters for the Baltimore Police Department 
(BPD). The goal of this service is to work closely with BPD leadership to establish policies and procedures for 
constitutional policing that further the City’s obligations under the federal Consent Decree. Activities performed by this 
service include defending BPD in any civil litigation in federal and state courts; representing the BPD in all labor issues; 
and providing legal guidance and advise to BPD on any issues related to the federal Consent Decree.'),
    ('SRV0872', 'This service represents the Mayor and City Council in workers’ compensation litigation. The goal of the service is to 
ensure City employees who are injured while working are paid the benefits to which they are legally entitled. Activities 
performed by this service include assisting claims adjusters at the City’s external adjusting company by giving legal and 
practical advice on claim handling, ensuring that legally non-compensable claims are not paid and that the Commission is 
aware of all the evidence of the Employee’s true limitations and symptoms so that they are not over compensated.'),
    ('SRV0873', 'This service was established in Fiscal 2022 to lead the City’s efforts to reduce broadband inequality and serve as Baltimore City government’s primary liaison with internal and external stakeholders in digital equity. The goal of this service is to permanently close the Digital Divide and improve digital literacy for seniors, youth, and other residents.  Activities performed by this service include digital literacy training, device distribution, marketing of funds available via the federal Affordable Connectivity Program and providing broadband connectivity and public WiFi to unserved and underserved communities.'),
    ('SRV0876', 'This service operates and provides programming for the City’s cable channel, CharmTV. The goal of the service is to 
provide residents to access public hearings and programming regarding City services. Activities performed by the service 
include broadcasting hearings (City Council, Board of Estimates, etc.), Mayoral press conferences and announcements, 
and other programming from City agencies.'),
    ('SRV0881', 'This service provides courthouse, courtroom and perimeter security for the City’s two Circuit Court buildings and the 
Juvenile Justice Center. The goal of this service is to ensure courtroom security; protect judges, courthouse employees, 
witnesses, defendants and member of the public. Approximately 5,000 persons enter the courthouses daily and one of the 
key activities of the Courthouse Security Officers includes screening all members of the public who enter the buildings for weapons and contraband.'),
    ('SRV0882', 'This service is responsible for serving all orders originating from Circuit Court including warrants, attachments, 
foreclosures, evictions, temporary protective orders, and levies. Activities performed by this service include processing 
approximately 70,000 court orders annually, housing and transporting approximately 1,100 prisoners annually, and 
collecting fines and costs assessed by the Circuit Court.'),
    ('SRV0883', 'This service is responsible for serving peace and protective orders issued by the District and Circuit Courts. Activities 
performed by the service include serving peace and protective orders under the Sheriff’s jurisdiction including domestic 
violence protective orders and general warrants, including the seizure of firearms.'),
    ('SRV0884', 'This service is responsible for serving all rent process issued from the Baltimore District Court, and executes evictions by court order. Activities performed by this service also includes operating and enforcing District Court writs, summonses, attachments, and levies. District Court Sheriff Services carry out approximately 145,000 summary ejectments and 64,000 eviction orders yearly.'),
    ('SRV0889', 'This Service is no longer provided. Its permanently closed'),
    ('SRV0893', 'This service oversees our Assistance in Community Integration Program (ACIS) a Medicaid-funded initiative to provide intensive case management and supportive services to individuals experiencing homelessness or at risk of institutional placement that also have two or more chronic health conditions. This program assists clients navigating critical systems with the goal of connecting clients to housing and healthcare.'),
    ('SRV0894', 'This service seeks to connect individuals experiencing homelessness with various resources to meet their basic needs. The goal of this service is to provide resources and ultimately connect individuals to stable housing. Activities performed by this service include operating the street outreach team and providing connections to case management resources.'),
    ('SRV0895', 'This service provides emergency sheltering for people experiencing homelessness. This goal of this service is provide emergency shelters, safe havens, transitional housing through the City’s winter shelter program. The primary activity performed by this service is supporting eight (8) emergency shelters across the City, including shelters which specifically serve families, unaccompanied homeless youth, and households fleeing intimate partner violence.'),
    ('SRV0896', 'This service provides medium and long-term housing assistance and supportive services to City residents experiencing homelessness through both rapid rehousing and permanent supportive housing programs. The goal of this service is to provide program participants with rental assistance and intensive case management services for as long as the household needs assistance. The primary activity performed by this service is contract management with service providers.'),
    ('SRV0899', 'This service is authorized by the Public General Laws of Maryland to conduct elections. The goal of this service is to ensure the proper and efficient registration of voters and conduct of elections. Activities performed by this service include training election judges and voting machine technicians, preparing election equipment, and overseeing the execution of elections.'),
    ('SRV0902', 'This service is responsible for overseeing all payments made on behalf of the City (excluding payroll and debt service payments). The goal of this service is to pay all invoices within 30 days of receipt. Activities performed by this service include invoice payments and disbursements as well as technical support to agencies and vendors on payment issues.'),
    ('SRV0903', 'This service provides citywide strategic planning and data management to drive innovation, enhance government operations, and improve the delivery of public services. The goal of this service is to leverage data, performance metrics, and accountability mechanisms to evaluate and optimize city services, while applying innovative design, digital tools, and data-driven approaches to address community needs and make government more responsive to residents. Activities performed by this service include administering the CitiStat program to improve agency performance and accountability, leading cross-agency research and implementation projects, developing and managing the citywide data warehouse and data products through the Product team, and overseeing data governance policies, open data initiatives, and transparency efforts through Open Baltimore - a publicly available data repository.'),
    ('SRV0905', 'This service provides the community collaborative network that is dedicated to empowering African American males by providing targeted resources, mentorship, advocacy, and community engagement initiatives.  Activities performed by this service include addressing systemic barriers, fostering personal and professional growth, and enhancing opportunities for success across various life domains, including education, employment, and leadership.'),
    ('SRV0906', 'This service champions equity, inclusion, and advocacy for Baltimore’s LGBTQ community by providing training to all City employees and agencies, fostering a workforce and services that are inclusive and affirming. The goal of the service is to ensure that Baltimore City remains a safe, affirming, and equitable environment where all residents, regardless of sexual orientation or gender identity, can thrive. Key activities performed by the service include: providing citywide cultural competency training and hosting community engagement activities.'),
    ('SRV0907', 'This service was abolished for FY27. 
This service provided support and oversight for major capital projects. The goal of the service was to support the efficient delivery of capital projects and assist in leveraging additional federal and state grants for capital projects. Key activities performed by the service included preparing grant applications for capital projects, providing targeted project oversight, and working to optimize public infrastructure delivery through systemic reform.'),
    ('SRV0908', 'This service coordinates citywide services geared towards meeting the needs of the City’s older adults.  The goal of the service is to connect and ensure older adults have access to all local, state and partners services and programs that relate and are important to their well-being. Key activities performed by the service include: providing administrative support and guidance to Commission on Aging, Resources, and Empowerment and work with the Director to promote agency efficiency and coordinate the delivery of programs and services for Older Adults Baltimore City.'),
    ('SRV0909', 'This service provides oversight for the administration and enforcement of the Zoning Code for Baltimore City. This service ensures that all construction activities and land uses in Baltimore City comply with the City’s Zoning Code. The goal of this service is to direct and enhance the furtherance of all new construction, renovations, and land use for existing and proposed development in Baltimore City to ensure compliance with the City’s Zoning Code. Key activities performed by this service include reviewing, filing, and forwarding of all applications for variances, conditional uses, and all other zoning related matters to the Board of Municipal and Zoning Appeals or the City Council, as necessary.'),
    ('SRV0910', 'This service supports an independent body of five members that oversee the Ethics Law, contained in Article 8 of the City Code. The goal of this service is to ensure that officials and employees serve the public fairly and independently by guarding against conflicts of interest and other improper conduct connected with City employment. The Ethics Law governs lobbyist registration and activity in the City. Activities performed by this service include investigating ethics complaints, promoting awareness of the Ethics Law, overseeing the financial disclosure and lobbying systems and processes, and answering all ethics-related questions from City officials, employees, and members of the public.'),
    ('SRV0911', 'This service focuses on creating a scalable, accessible, and user-centered experience for people and entities that interact with the City of Baltimore''s digital products. The goal of this service is to support equitable access to reliable information and City Services. Activities performed by this service include managing website content and hosting, implementing the transition to the City’s new website, and improving user experience and accessibility to the City’s  digital products.'),
    ('SRV0912', 'The service is responsible for the maintenance and repair of recreation and parks buildings and swimming pools. Its primary objective is to ensure safe public access to these facilities. The service''s activities include: general maintenance and repairs, renovations, electrical services, lighting, plumbing, pool maintenance and inspections, HVAC services, contract management, and other services to support the agency’s core activities.'),
    ('SRV0913', 'This service oversees all grant management activities in the City and develops standard operating procedures and guidelines to ensure grant management best practice. The goal of this service is to provide oversight and guidance to all City agencies, offices and departments regarding official grant policies and procedures and to ensure compliance. Activities performed by this service include developing guidance, advising agencies on grant practices, and reviewing agency grant activity for annual audit purposes.'),
    ('SRV0914', 'This service provides executive leadership and administrative support across all four services within the Office of Equity and Civil Rights. The goal of this service is to ensure effective coordination, resource management, and policy implementation to advance the agency’s mission to carry out activities to eliminate inequity, inequality, and discrimination. Activities performed by this service include budget development and fiscal operations, human resources management, strategic planning, communications and community partnerships, contract administration, program management, grants management, performance measurement, information technology support, and ensuring compliance with city, state, and federal regulations across all divisions.'),
    ('SRV0915', 'This service ensures that businesses operating within the City of Baltimore comply with the Baltimore City Code, with an emphasis on corporate rules and regulations. The goals are to ensure that Baltimore City’s self-reported taxes, including hotel taxes, parking taxes, and other taxes and fees, are paid on time. Key activities performed by the service include assisting other departments with negotiating complex multi-year contracts and manages corporate revenue collection efforts, leading to the recovery of dollars owed to the City.'),
    ('SRV0916', 'This service is responsible for oversight and coordination of grants awarded through the Opioid Restitution Fund. The goal of this service is to ensure grants awarded through this fund are implemented in alignment with stated outcomes and program requirements. Activities performed by this service include: developing and overseeing grant agreements, providing technical assistance to community based organizations, and providing overall direction and guidance regarding the use of these funds.'),
    ('SRV0917', 'This service provides grants to organizations named as part of the settlement from the City’s ongoing opioid litigation. This includes $87.0 million awarded to 22 community-based organizations. Funding from these grants is paid out annually based on the terms of individual grant agreements.'),
    ('SRV0918', 'This service is responsible for coordinating the deployment of Opioid Restitution Funds. The goal of this service is to coordinate with community partners and City agencies to invest Opioid Restitution Funds in alignment with the August 2024 Executive Order establishing the Opioid Restitution Fund. Key activities performed by this service include supporting the Restitution Advisory Board and overseeing the community needs assessment.'),
    ('SRV0919', 'This service is responsible for managing the City''s municipal identification (ID) program. The goal of this service is to support residents, particularly those unable to obtain a state government-issued identification, with a valid City identification that can be used to access City services, enter city-managed facilities, and interact with local law enforcement. Activities performed by this service include working with businesses to develop a benefit program that entices residents to obtain and utilize the card; working with City agencies to ensure the municipal ID card is accepted for services they provide; and marketing and issuing municipal ID cards to City residents.'),
    ('SRV0920', 'This service is responsible for coordinating art, events, nightlife and film in a centralized office. The goal of this service is to shape the future of Baltimore’s live events, cultural workforce, creative economy, nightlife, and film industry.'),
    ('SRV0921', 'This service ensures that businesses are properly licensed, comply with regulations, and operate fairly. The goals of this service are to resolve complaints related to unfair, abusive, or deceptive trade practices and to protect consumers and maintain a transparent marketplace. Activities performed by this service include four core duties: licensing oversight, consumer protection enforcement, regulatory compliance, and formal adjudication through its Board.'),
    ('SRV0922', 'This service manages the Clean Corps program in the Department of Planning. The goal of this service is to coordinate with nonprofit partners, community stakeholders, and partner agencies to implement a proactive and preventative maintenance strategy for neighborhood cleanliness and workforce development. Activities include coordinating program and service delivery across neighborhoods; managing contracts and vendor performance; resolving rapid-response constituent service requests; integrating citywide service data to identify gaps and improve performance; aligning employment and training pathways between agencies and partners; and supporting community engagement and building resident capacity.'),
    ('SRV0923', 'This service contains MONSE''s executive functions to include agency management, finance, data analytics, and communications, as well as the staff that support these functions. The goal of this service is to support back-office activities that allow the agency operations to move forward. Activities performed by this service include office operations, public communication, financial management, procurement, grant-making and contract management, and data analytics.'),
    ('SRV0924', 'This service contains MONSE’s violence prevention programming and the staff that support it. The Community Violence Intervention (CVI) ecosystem together with focused deterrence through the Group Violence Reduction Strategy (GVRS) constitute Baltimore’s dual approaches to gun violence prevention. Activities supported by this service include GVRS, Safe Streets, Hospital-Based Violence Intervention Programming (HVIP), and School-Based Violence Intervention programming.'),
    ('SRV0925', 'This service contains MONSE''s Victim Services Programming and support staff. MONSE’s Victim Services team fills gaps and supports survivors of gun violence, intimate partner violence (IPV), and other trauma. This includes primary, secondary, and tertiary victims. Activities performed by this service include the management of the Baltimore City Visitation Center, intensive case management, other direct victim supports, anti-human trafficking work, and IPV prevention.'),
    ('SRV0926', 'This service contains MONSE’s Re-Entry programming and support staff. The goal of this service is to provide meaningful supports and programming for returning citizens. Activities performed by this service include safe return planning, re-entry services, and the Re-Entry Action Council.'),
    ('SRV0927', 'This service contains MONSE''s community engagement and youth programming and the staff that support it. The goal of this service is to facilitate meaningful engagement with residents to co-produce public safety, rebuild government trust, and address community concerns through collaborative strategies. Activities performed by this service include youth diversion, Coordinated Neighborhood Stabilization Responses (CNSR), Peace Mobile operations, and Summer Youth Engagement.'),
    ('SRV0928', 'This service leads the preparation of the City’s capital budget and six-year Capital Improvement Program. The goal of this service is to develop a six-year capital improvement program that addresses the City’s infrastructure needs while improving the quality of life for City residents. Activities performed by this service include developing the capital budget, six-year CIP, loan authorization, capital transfers, de-appropriations, supplementals, local impact aid spending plans, reports, etc.'),
    ('SRV0929', 'This service leads the preparation of the City’s capital budget and six-year Capital Improvement Program. The goal of this service is to develop a six-year capital improvement program that addresses the City’s infrastructure needs while improving the quality of life for City residents. Activities performed by this service include developing the capital budget, six-year CIP, loan authorization, capital transfers, de-appropriations, supplementals, local impact aid spending plans, reports, etc.'),
    ('SRV0930', 'This service supports the behavioral health and well‑being of individuals, families, and communities by delivering programs focused on prevention, early intervention, harm reduction, treatment access, and long‑term recovery support. The goal of this service is to minimize the negative health and social impacts associated with substance use and to reduce fatal and nonfatal overdoses by identifying risks early, expanding access to life‑saving interventions, and connecting people to supportive services for substance use and mental health needs. Activities performed by this service include providing naloxone training and distribution, offering harm‑reduction services for people who use or inject drugs, delivering substance use prevention education, allocating resources to providers for mental health and substance use services, conducting overdose fatality reviews, and supporting treatment and recovery services for individuals experiencing mental health or substance use disorders.'),
    ('SRV0931', 'This service is responsible for advising on matters relating to foreign born communities. The goal of this service is to coordinate City outreach and support of immigrant communities living in the City. Major activities performed by the service include: providing technical assistance to agencies on serving these populations, managing the City’s language access program, and overseeing communications and outreach to ethnic civic groups, and responding to needs of immigrants.')
) AS seed(service_id, service_description)
WHERE service.service_id = seed.service_id;
